import type { SessionWorkspace } from '@/features/home/domain/session-workspace';

export const homeWorkspaceQueryKey = ['home-workspace'] as const;

export async function fetchHomeWorkspace(): Promise<SessionWorkspace> {
  const response = await fetch('/api/workspace', {
    headers: {
      Accept: 'application/json',
    },
  });

  if (!response.ok) {
    throw new Error(`Failed to load workspace: ${response.status}`);
  }

  return response.json() as Promise<SessionWorkspace>;
}

