export type HomeView = 'kanban' | 'terminal';

const tabs = [
  { label: 'Kanban', value: 'kanban', widthClassName: 'w-[83px]' },
  { label: 'Terminal', value: 'terminal', widthClassName: 'w-[100px]' },
] satisfies Array<{
  label: string;
  value: HomeView;
  widthClassName: string;
}>;

export function SessionViewTabs(props: {
  className?: string;
  onValueChange: (value: HomeView) => void;
  value: HomeView;
}) {
  return (
    <div
      className={cn(
        'flex h-9 w-[183px] items-center overflow-hidden border border-border bg-background',
        props.className
      )}
      role="tablist"
      aria-label="Session view"
    >
      {tabs.map((tab, index) => {
        const isSelected = props.value === tab.value;

        return (
          <button
            key={tab.value}
            type="button"
            className={cn(
              'flex h-9 shrink-0 items-center justify-center px-4 text-sm leading-5 font-medium outline-none focus-visible:ring-[3px] focus-visible:ring-ring/50',
              tab.widthClassName,
              index < tabs.length - 1 && 'border-r border-border',
              isSelected
                ? 'bg-sidebar-primary text-sidebar-primary-foreground hover:bg-sidebar-primary'
                : 'bg-background text-foreground hover:bg-accent hover:text-accent-foreground'
            )}
            role="tab"
            aria-selected={isSelected}
            tabIndex={isSelected ? 0 : -1}
            data-view={tab.value}
            onClick={() => props.onValueChange(tab.value)}
            onKeyDown={(event) => {
              if (event.key !== 'ArrowLeft' && event.key !== 'ArrowRight') {
                return;
              }

              event.preventDefault();

              const nextIndex =
                event.key === 'ArrowRight'
                  ? (index + 1) % tabs.length
                  : (index - 1 + tabs.length) % tabs.length;
              const nextTab = tabs[nextIndex];

              if (!nextTab) {
                return;
              }

              props.onValueChange(nextTab.value);
              event.currentTarget.parentElement
                ?.querySelector<HTMLButtonElement>(
                  `[data-view="${nextTab.value}"]`
                )
                ?.focus();
            }}
          >
            {tab.label}
          </button>
        );
      })}
    </div>
  );
}

