  homeWorkspaceQueryOptions,
} from '@/features/home/data/workspace';
import {
  defaultHomeWorkspacePreferences,
  type HomeWorkspacePreferences,
  readHomeWorkspacePreferences,
  writeHomeWorkspacePreferences,
} from '@/features/home/data/workspace-preferences';
import {
  getKanbanColumns,
  getSelectedWorkerSession,
  getTerminalSession,
  getWorkerSessionGroups,
  getWorkerSessionSelectionKey,
  type WorkerSessionState,
  workerSessionStates,
  withSelectedWorkerSession,
} from '@/features/home/domain/session-workspace';
import { OrchestratorWorkspaceTemplate } from '@/features/home/templates/orchestrator-workspace-template';

export function OrchestratorHomePage() {
  const [hasRestoredPreferences, setHasRestoredPreferences] = useState(false);
  const [view, setView] = useState<HomeView>(
    defaultHomeWorkspacePreferences.view
  );
  const [sidebarOpen, setSidebarOpen] = useState(
    defaultHomeWorkspacePreferences.sidebarOpen
  );
  const workspaceQuery = useQuery(homeWorkspaceQueryOptions());
  const workspace = workspaceQuery.data ?? fallbackHomeWorkspace;
  const [selectedWorkerSessionKey, setSelectedWorkerSessionKey] = useState<
    string | undefined
  >(defaultHomeWorkspacePreferences.selectedWorkerSessionKey);
  const [selectedTerminalSessionKey, setSelectedTerminalSessionKey] = useState<
    string | undefined
  >(defaultHomeWorkspacePreferences.selectedTerminalSessionKey);
  const [openProjectIds, setOpenProjectIds] = useState<string[] | undefined>(
    defaultHomeWorkspacePreferences.openProjectIds
  );
  const [openWorkerSessionGroupIds, setOpenWorkerSessionGroupIds] = useState<
    WorkerSessionState[] | undefined
  >(defaultHomeWorkspacePreferences.openWorkerSessionGroupIds);
  const sessions = useMemo(
    () =>
      withSelectedWorkerSession(workspace.sessions, selectedWorkerSessionKey),
    [selectedWorkerSessionKey, workspace.sessions]
  );
  const selectedWorkerSession = getSelectedWorkerSession(sessions);
  const terminalSessions = useMemo(
    () => [...(workspace.orchestrators ?? []), ...sessions],
    [sessions, workspace.orchestrators]
  );
  const selectedTerminalSession =
    getTerminalSession(terminalSessions, selectedTerminalSessionKey) ??
    selectedWorkerSession ??
    terminalSessions[0];
  const selectedProjectId =
    selectedTerminalSession?.project ?? workspace.activeProjectId;
  const defaultOpenProjectIds = useMemo(
    () =>
      workspace.projects.some((project) => project.id === selectedProjectId)
        ? [selectedProjectId]
        : [],
    [selectedProjectId, workspace.projects]
  );
  const kanbanColumns = useMemo(() => getKanbanColumns(sessions), [sessions]);
  const workerSessionGroups = useMemo(
    () => getWorkerSessionGroups(sessions),
    [sessions]
  );
  const workspaceState = workspaceQuery.isPending
    ? 'loading'
    : workspaceQuery.isError
      ? 'error'
      : sessions.length === 0
        ? 'empty'
        : 'ready';

  useEffect(() => {
    const preferences = readHomeWorkspacePreferences();
    const selectedSessionKey =
      preferences.selectedWorkerSessionKey ??
      preferences.selectedTerminalSessionKey;

    setView(preferences.view);
    setSidebarOpen(preferences.sidebarOpen);
    setSelectedWorkerSessionKey(selectedSessionKey);
    setSelectedTerminalSessionKey(
      preferences.selectedTerminalSessionKey ?? selectedSessionKey
    );
    setOpenProjectIds(preferences.openProjectIds);
    setOpenWorkerSessionGroupIds(preferences.openWorkerSessionGroupIds);
    setHasRestoredPreferences(true);
  }, []);

  useEffect(() => {
    if (!hasRestoredPreferences || !selectedWorkerSession) {
      return;
    }

    const selectedKey = getWorkerSessionSelectionKey(selectedWorkerSession);
    setSelectedWorkerSessionKey((currentSessionKey) =>
      currentSessionKey === selectedKey ? currentSessionKey : selectedKey
    );
  }, [hasRestoredPreferences, selectedWorkerSession]);

  useEffect(() => {
    if (!hasRestoredPreferences || !selectedTerminalSession) {
      return;
    }

    const selectedKey = getWorkerSessionSelectionKey(selectedTerminalSession);
    setSelectedTerminalSessionKey((currentSessionKey) => {
      if (getTerminalSession(terminalSessions, currentSessionKey)) {
        return currentSessionKey;
      }

      return selectedKey;
    });
  }, [hasRestoredPreferences, selectedTerminalSession, terminalSessions]);

  useEffect(() => {
    if (!hasRestoredPreferences) {
      return;
    }

    writeHomeWorkspacePreferences({
      openProjectIds,
      openWorkerSessionGroupIds,
      selectedTerminalSessionKey,
      selectedWorkerSessionKey,
      sidebarOpen,
      view,
    });
  }, [
    hasRestoredPreferences,
    openProjectIds,
    openWorkerSessionGroupIds,
    selectedTerminalSessionKey,
    selectedWorkerSessionKey,
    sidebarOpen,
    view,
  ]);

  const persistHomeWorkspacePreferences = useCallback(
    (preferences: Partial<HomeWorkspacePreferences>) => {
      writeHomeWorkspacePreferences({
        openProjectIds,
        openWorkerSessionGroupIds,
        selectedTerminalSessionKey,
        selectedWorkerSessionKey,
        sidebarOpen,
        view,
        ...preferences,
      });
    },
    [
      openProjectIds,
      openWorkerSessionGroupIds,
      selectedTerminalSessionKey,
      selectedWorkerSessionKey,
      sidebarOpen,
      view,
    ]
  );

  const handleSidebarOpenChange = useCallback(
    (open: boolean) => {
      persistHomeWorkspacePreferences({ sidebarOpen: open });
      setSidebarOpen(open);
    },
    [persistHomeWorkspacePreferences]
  );

  const handleProjectOpenChange = useCallback(
    (projectId: string, open: boolean) => {
      const nextOpenProjectIds = updateOpenIds(
        openProjectIds,
        projectId,
        open,
        defaultOpenProjectIds
      );

      persistHomeWorkspacePreferences({ openProjectIds: nextOpenProjectIds });
      setOpenProjectIds(nextOpenProjectIds);
    },
    [defaultOpenProjectIds, openProjectIds, persistHomeWorkspacePreferences]
  );

  const handleWorkerSessionGroupOpenChange = useCallback(
    (groupId: WorkerSessionState, open: boolean) => {
      const nextOpenWorkerSessionGroupIds = updateOpenIds(
        openWorkerSessionGroupIds,
        groupId,
        open,
        workerSessionStates
      );

      persistHomeWorkspacePreferences({
        openWorkerSessionGroupIds: nextOpenWorkerSessionGroupIds,
      });
      setOpenWorkerSessionGroupIds(nextOpenWorkerSessionGroupIds);
    },
    [openWorkerSessionGroupIds, persistHomeWorkspacePreferences]
  );

  const handleViewChange = useCallback(
    (nextView: HomeView) => {
      persistHomeWorkspacePreferences({ view: nextView });
      startTransition(() => {
        setView((currentView) =>
          currentView === nextView ? currentView : nextView
        );
      });
    },
    [persistHomeWorkspacePreferences]
  );

  const handleWorkerSessionOpen = useCallback(
    (selectionKey: string) => {
      const selectedProjectId = getProjectIdFromSelectionKey(selectionKey);
      const nextOpenProjectIds = selectedProjectId
        ? updateOpenIds(
            openProjectIds,
            selectedProjectId,
            true,
            defaultOpenProjectIds
          )
        : openProjectIds;

      persistHomeWorkspacePreferences({
        openProjectIds: nextOpenProjectIds,
        selectedTerminalSessionKey: selectionKey,
        selectedWorkerSessionKey: selectionKey,
        view: 'terminal',
      });
      startTransition(() => {
        setSelectedWorkerSessionKey(selectionKey);
        setSelectedTerminalSessionKey(selectionKey);
        setOpenProjectIds(nextOpenProjectIds);
        setView('terminal');
      });
    },
    [defaultOpenProjectIds, openProjectIds, persistHomeWorkspacePreferences]
  );

  const handleTerminalSessionOpen = useCallback(
    (selectionKey: string) => {
      const selectedProjectId = getProjectIdFromSelectionKey(selectionKey);
      const nextOpenProjectIds = selectedProjectId
        ? updateOpenIds(
            openProjectIds,
            selectedProjectId,
            true,
            defaultOpenProjectIds
          )
        : openProjectIds;

      persistHomeWorkspacePreferences({
        openProjectIds: nextOpenProjectIds,
        selectedTerminalSessionKey: selectionKey,
        view: 'terminal',
      });
      startTransition(() => {
        setSelectedTerminalSessionKey(selectionKey);
        setOpenProjectIds(nextOpenProjectIds);
        setView('terminal');
      });
    },
    [defaultOpenProjectIds, openProjectIds, persistHomeWorkspacePreferences]
  );

  return (
    <OrchestratorWorkspaceTemplate
      sidebarOpen={sidebarOpen}
      onSidebarOpenChange={handleSidebarOpenChange}
      primarySidebar={
        <ProjectOrchestratorSidebar
          onOrchestratorSessionSelect={handleTerminalSessionOpen}
          onProjectOpenChange={handleProjectOpenChange}
          onWorkerSessionGroupOpenChange={handleWorkerSessionGroupOpenChange}
          projects={workspace.projects}
          selectedProjectId={selectedProjectId}
          selectedTerminalSessionKey={selectedTerminalSessionKey}
          openProjectIds={openProjectIds}

